  1	import * as React from 'react';
  2	import { connect } from 'react-redux';
  3	import { KialiDispatch } from 'types/Redux';
  4	import _round from 'lodash/round';
  5	import { Button, ButtonVariant, Card, CardBody, Grid, GridItem, Tooltip } from '@patternfly/react-core';
  6	import { InfoAltIcon, WarningTriangleIcon } from '@patternfly/react-icons';
  7	import { JaegerTrace, RichSpanData } from 'types/TracingInfo';
  8	import { TracingTraceTitle } from './TracingTraceTitle';
  9	import { GraphType } from 'types/Graph';
 10	import { FormattedTraceInfo, shortIDStyle } from './FormattedTraceInfo';
 11	import { PFColors } from 'components/Pf/PfColors';
 12	import { KialiAppState } from 'store/Store';
 13	import { TracingThunkActions } from 'actions/TracingThunkActions';
 14	import { getTraceId } from 'utils/SearchParamUtils';
 15	import { average } from 'utils/MathUtils';
 16	import {
 17	  averageSpanDuration,
 18	  buildQueriesFromSpans,
 19	  isSimilarTrace,
 20	  reduceMetricsStats,
 21	  StatsMatrix
 22	} from 'utils/tracing/TraceStats';
 23	import { TraceLabels } from './TraceLabels';
 24	import { TargetKind } from 'types/Common';
 25	import { MetricsStatsQuery } from 'types/MetricsOptions';
 26	import { MetricsStatsThunkActions } from 'actions/MetricsStatsThunkActions';
 27	import { renderTraceHeatMap } from './StatsComparison';
 28	import { HeatMap, healthColorMap } from 'components/HeatMap/HeatMap';
 29	import { formatDuration, sameSpans } from 'utils/tracing/TracingHelper';
 30	import { TracingUrlProvider } from 'types/Tracing';
 31	import _ from 'lodash';
 32	
 33	type ReduxProps = {
 34	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean, cluster?: string) => void;
 35	  setTraceId: (cluster?: string, traceId?: string) => void;
 36	};
 37	
 38	type StateProps = {
 39	  isStatsMatrixComplete: boolean;
 40	  statsMatrix?: StatsMatrix;
 41	  trace?: JaegerTrace;
 42	};
 43	
 44	type Props = ReduxProps &
 45	  StateProps & {
 46	    cluster?: string;
 47	    namespace: string;
 48	    otherTraces: JaegerTrace[];
 49	    provider?: string;
 50	    target: string;
 51	    targetKind: TargetKind;
 52	    tracingURLProvider?: TracingUrlProvider;
 53	  };
 54	
 55	interface State {}
 56	
 57	class TraceDetailsComponent extends React.Component<Props, State> {
 58	  constructor(props: Props) {
 59	    super(props);
 60	    const urlTrace = getTraceId();
 61	
 62	    if (urlTrace && urlTrace !== props.trace?.traceID) {
 63	      props.setTraceId(this.props.cluster, urlTrace);
 64	    } else if (!urlTrace && props.trace) {
 65	      // Remove old stored selected trace
 66	      props.setTraceId(this.props.cluster, undefined);
 67	    }
 68	
 69	    this.state = { completeMetricsStats: false };
 70	  }
 71	
 72	  componentDidMount(): void {
 73	    if (this.props.trace) {
 74	      this.fetchComparisonMetrics(this.props.trace.spans);
 75	    }
 76	  }
 77	
 78	  componentDidUpdate(prevProps: Readonly<Props>): void {
 79	    if (this.props.trace && !sameSpans(prevProps.trace?.spans || [], this.props.trace.spans)) {
 80	      this.fetchComparisonMetrics(this.props.trace.spans);
 81	    }
 82	  }
 83	
 84	  private fetchComparisonMetrics(spans: RichSpanData[]): void {
 85	    const queries = buildQueriesFromSpans(spans, false);
 86	    this.props.loadMetricsStats(queries, false, this.props.cluster);
 87	  }
 88	
 89	  private getGraphURL = (traceID: string): string => {
 90	    let graphType: GraphType = GraphType.APP;
 91	
 92	    switch (this.props.targetKind) {
 93	      case 'service':
 94	        graphType = GraphType.SERVICE;
 95	        break;
 96	      case 'workload':
 97	        graphType = GraphType.WORKLOAD;
 98	        break;
 99	    }
100	
101	    return `/graph/namespaces?graphType=${graphType}&injectServiceNodes=true&namespaces=${this.props.namespace}&traceId=${traceID}`;
102	  };
103	
104	  private renderSimilarHeatmap = (
105	    similarTraces: JaegerTrace[],
106	    traceDuration: number,
107	    avgSpanDuration: number | undefined
108	  ): React.ReactNode => {
109	    const similarMeanDuration = average(similarTraces, trace => trace.duration);
110	    const similarSpanDurations = similarTraces
111	      .map(t => averageSpanDuration(t))
112	      .filter(d => d !== undefined) as number[];
113	
114	    const similarMeanAvgSpanDuration = average(similarSpanDurations, d => d);
115	    const genDiff = (a: number | undefined, b: number | undefined): number | undefined =>
116	      a && b ? (a - b) / 1000 : undefined;
117	    const similarTracesToShow = similarTraces.slice(0, 8);
118	
119	    const similarMatrixHeaders = similarTracesToShow
120	      .map(t => {
121	        const info = new FormattedTraceInfo(t);
122	        return (
123	          <Tooltip
124	            content={
125	              <>
126	                {info.name()}
127	                <span className={shortIDStyle}>{info.shortID()}</span>
128	                <small>({info.fromNow()})</small>
129	              </>
130	            }
131	          >
132	            <Button
133	              style={{ paddingLeft: 0, paddingRight: '0.25rem', fontSize: '0.75rem' }}
134	              variant={ButtonVariant.link}
135	              onClick={() => this.props.setTraceId(t.traceID)}
136	            >
137	              {info.shortID()}
138	            </Button>
139	          </Tooltip>
140	        );
141	      })
142	      .concat([<>Mean</>]);
143	
144	    const similarMatrix = similarTracesToShow
145	      .map(t => {
146	        const avgSpans = averageSpanDuration(t);
147	        return [genDiff(traceDuration, t.duration), genDiff(avgSpanDuration, avgSpans)];
148	      })
149	      .concat([[genDiff(traceDuration, similarMeanDuration), genDiff(avgSpanDuration, similarMeanAvgSpanDuration)]]);
150	
151	    return (
152	      <HeatMap
153	        xLabels={similarMatrixHeaders}
154	        yLabels={[`Full duration`, `Spans average`]}
155	        data={similarMatrix}
156	        displayMode="large"
157	        colorMap={healthColorMap}
158	        dataRange={{ from: -10, to: 10 }}
159	        colorUndefined={PFColors.ColorLight200}
160	        valueFormat={v => `${v > 0 ? '+' : ''}${_round(v, 1)}`}
161	        tooltip={(x, _, v) => {
162	          // Build explanation tooltip
163	          const slowOrFast = v > 0 ? 'slower' : 'faster';
164	          const diff = _round(Math.abs(v), 2);
165	          const versus =
166	            x === similarTracesToShow.length
167	              ? 'the mean of all similar traces on chart'
168	              : similarTracesToShow[x].traceID;
169	
170	          return `This trace was ${diff}ms ${slowOrFast} than ${versus}`;
171	        }}
172	      />
173	    );
174	  };
175	
176	  render(): JSX.Element | null {
177	    const { trace, otherTraces } = this.props;
178	
179	    if (!trace) {
180	      return null;
181	    }
182	
183	    const formattedTrace = new FormattedTraceInfo(trace);
184	
185	    // Compute a bunch of stats
186	    const avgSpanDuration = averageSpanDuration(trace);
187	    const similarTraces = otherTraces.filter(t => t.traceID !== trace.traceID && isSimilarTrace(t, trace));
188	
189	    const comparisonLink =
190	      similarTraces.length > 0
191	        ? this.props.tracingURLProvider?.ComparisonUrl(trace.traceID, ..._.map(similarTraces, t => t.traceID))
192	        : undefined;
193	
194	    return (
195	      <Card isCompact>
196	        <TracingTraceTitle
197	          formattedTrace={formattedTrace}
198	          externalURL={this.props.tracingURLProvider?.TraceUrl(trace)}
199	          graphURL={this.getGraphURL(trace.traceID)}
200	          comparisonURL={comparisonLink}
201	          traceId={trace.traceID}
202	        />
203	        <CardBody>
204	          <Grid style={{ marginTop: '1.25rem' }}>
205	            <GridItem span={3}>
206	              <TraceLabels spans={trace.spans} oneline={false} />
207	            </GridItem>
208	
209	            <GridItem span={3}>
210	              <Tooltip content={<>The full trace duration is (trace end time) - (trace start time).</>}>
211	                <strong>Full duration: </strong>
212	              </Tooltip>
213	
214	              {formatDuration(trace.duration)}
215	              <br />
216	
217	              <Tooltip
218	                content={
219	                  <>
220	                    The average duration of all spans within the trace. It differs from full duration, as spans can run
221	                    in parallel, or there can be dead time between spans.
222	                  </>
223	                }
224	              >
225	                <strong>Spans average duration: </strong>
226	              </Tooltip>
227	
228	              {avgSpanDuration ? formatDuration(avgSpanDuration) : 'n/a'}
229	              <br />
230	              <br />
231	
232	              {this.props.statsMatrix && (
233	                <>
234	                  <strong>Compared with metrics: </strong>
235	                  {renderTraceHeatMap(this.props.statsMatrix, false)}
236	                  {!this.props.isStatsMatrixComplete && (
237	                    <>
238	                      <WarningTriangleIcon /> Incomplete data, check Span Details
239	                    </>
240	                  )}
241	                </>
242	              )}
243	            </GridItem>
244	
245	            <GridItem span={6}>
246	              <Tooltip content="Traces are identified as similar based on counting the number of spans and the occurrences of operation names. Only traces currently on the chart are processed.">
247	                <>
248	                  <InfoAltIcon /> <strong>Similar traces</strong>
249	                  <br />
250	                </>
251	              </Tooltip>
252	
253	              {similarTraces.length > 0
254	                ? this.renderSimilarHeatmap(similarTraces, trace.duration, avgSpanDuration)
255	                : 'No similar traces found'}
256	            </GridItem>
257	          </Grid>
258	        </CardBody>
259	      </Card>
260	    );
261	  }
262	}
263	
264	const mapStateToProps = (state: KialiAppState): StateProps => {
265	  if (state.tracingState.selectedTrace) {
266	    const { matrix, isComplete } = reduceMetricsStats(state.tracingState.selectedTrace, state.metricsStats.data, false);
267	
268	    return {
269	      trace: state.tracingState.selectedTrace,
270	      statsMatrix: matrix,
271	      isStatsMatrixComplete: isComplete
272	    };
273	  }
274	
275	  return {
276	    trace: state.tracingState.selectedTrace,
277	    isStatsMatrixComplete: false
278	  };
279	};
280	
281	const mapDispatchToProps = (dispatch: KialiDispatch): ReduxProps => ({
282	  setTraceId: (cluster?: string, traceId?: string) => dispatch(TracingThunkActions.setTraceId(cluster, traceId)),
283	  loadMetricsStats: (queries: MetricsStatsQuery[], isCompact: boolean) =>
284	    dispatch(MetricsStatsThunkActions.load(queries, isCompact))
285	});
286	
287	export const TraceDetails = connect(mapStateToProps, mapDispatchToProps)(TraceDetailsComponent);

